def hash_sensitive_value(value, salt=None):
    if salt is None:
        salt = os.urandom(32)
    hashed = hashlib.pbkdf2_hmac('sha256', value.encode('utf-8'), salt, 100000)
    return hashed.hex()


def mask_value(value, visible_chars=2):
    if not value or len(value) <= visible_chars:
        return '*' * len(value) if value else ''
    return value[:visible_chars] + '*' * (len(value) - visible_chars)


def extract_db_info_from_connection_string(conn_string):
    try:
        if conn_string.startswith('postgresql://') or conn_string.startswith('postgres://'):
            parsed = urlparse(conn_string)
            return {
                'username': parsed.username or '',
                'password': parsed.password or '',
                'host': parsed.hostname or '',
                'port': parsed.port or 5432,
                'database': parsed.path.lstrip('/') if parsed.path else ''
            }
        else:
            params = {}
            for part in conn_string.split():
                if '=' in part:
                    key, value = part.split('=', 1)
                    params[key] = value
            return {
                'username': params.get('user', ''),
                'password': params.get('password', ''),
                'host': params.get('host', ''),
                'port': params.get('port', '5432'),
                'database': params.get('dbname', '')
            }
    except Exception:
        return None


